import DirectMessageItem from "./DirectMessageItem";
import classes from "./DirectMessageList.module.css";
import DirectMessagesHeader from "./DirectMessagesHeader";
// import FriendsIcon from "../UI/FriendsIcon";

const DirectMessageList = (props) => {
  return (
    <ul className={classes["item-list"]}>
      <div className={classes["gap"]}></div>

      {/* <DirectMessageItem
        text="Friends"
        svg={<FriendsIcon></FriendsIcon>}
      ></DirectMessageItem> */}

      <DirectMessageItem
        text="Friends"
        avatar="https://animedao.to/images/call-of-the-night.jpg"
        link="/friends"
      ></DirectMessageItem>

      <DirectMessagesHeader></DirectMessagesHeader>

      {props.directMessages.map((dm) => (
        <DirectMessageItem
          text={dm.username}
          avatar={"https://animedao.to/images/call-of-the-night.jpg"}
          link={`/${props.chatId}`}
        ></DirectMessageItem>
      ))}

      <DirectMessageItem
        text="Bob"
        avatar="https://animedao.to/images/call-of-the-night.jpg"
        link="/bob"
      ></DirectMessageItem>
    </ul>
  );
};

export default DirectMessageList;
